import{_ as e,o,c as r,a2 as a}from"./chunks/framework.Bix3-HpO.js";const h=JSON.parse('{"title":"Demo Import","description":"Akurai Theme Demo Import","frontmatter":{"title":"Demo Import","description":"Akurai Theme Demo Import","weight":140,"extra":{"order":140},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai/demo-import"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai/demo-import"}],["meta",{"property":"og:title","content":"Demo Import"}],["meta",{"property":"og:description","content":"Akurai Theme Demo Import"}],["meta",{"name":"twitter:title","content":"Demo Import"}],["meta",{"name":"twitter:description","content":"Akurai Theme Demo Import"}]]},"headers":[],"relativePath":"docs/akurai/demo-import.md","filePath":"docs/akurai/demo-import.md"}'),n={name:"docs/akurai/demo-import.md"};function i(m,t,d,c,s,l){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="demo-import" tabindex="-1">Demo Import <a class="header-anchor" href="#demo-import" aria-label="Permalink to &quot;Demo Import&quot;">​</a></h1><p>One Click Demo Import for Akurai theme.</p><h2 id="how-to-import-demo-content" tabindex="-1">How to import demo content <a class="header-anchor" href="#how-to-import-demo-content" aria-label="Permalink to &quot;How to import demo content&quot;">​</a></h2><p>Instead of starting from scratch, with Akurai you have options to import demo content and make your adjustments.</p><h3 id="one-click-demo-import" tabindex="-1">One Click Demo Import <a class="header-anchor" href="#one-click-demo-import" aria-label="Permalink to &quot;One Click Demo Import&quot;">​</a></h3><p>With <strong>One Click Demo Import</strong> option you can import demo content, as well as customizations and widgets exactly the way they are on demo websites.</p><p>You need to install <a href="https://wordpress.org/plugins/one-click-demo-import/" target="_blank" rel="noreferrer">One Click Demo Import</a> plugin from WP plugin directory. Once it&#39;s installed and activated, there will be a new submenu item in your WP dashboard → Appearance called &quot;<strong>Akurai Demo Import</strong>&quot;.</p><p>Visit that page, select the demo website and import it. You can also install optional plugins the during import process. Once the import is completed your website will like the demo you selected.</p><p>If for some reason you get an error when trying to import the demo, try switching to manual method and upload the below files:</p><ul><li>Atlanta demo - <a href="https://media.dinomatic.com/demo/contents/atlanta.xml" target="_blank" rel="noreferrer">content</a>, <a href="https://media.dinomatic.com/demo/customizer/atlanta.dat" target="_blank" rel="noreferrer">customizer</a>, <a href="https://media.dinomatic.com/demo/widgets/atlanta.wie" target="_blank" rel="noreferrer">widgets</a></li><li>Dortmund demo - <a href="https://media.dinomatic.com/demo/contents/dortmund.xml" target="_blank" rel="noreferrer">content</a>, <a href="https://media.dinomatic.com/demo/customizer/dortmund.dat" target="_blank" rel="noreferrer">customizer</a>, <a href="https://media.dinomatic.com/demo/widgets/dortmund.wie" target="_blank" rel="noreferrer">widgets</a></li></ul><h3 id="manual-content-import" tabindex="-1">Manual Content Import <a class="header-anchor" href="#manual-content-import" aria-label="Permalink to &quot;Manual Content Import&quot;">​</a></h3><p>If you prefer to customize the theme on your own, you can download a <code>.xml</code> file from your DinoMatic account that contains the demo content. After that you can import it to your new website using WP Importer following <a href="https://wordpress.org/support/article/importing-content/#wordpress" target="_blank" rel="noreferrer">simple steps</a>. It will not import the customizations or widgets to your website.</p>',12)])])}const u=e(n,[["render",i]]);export{h as __pageData,u as default};
